{!REQUIRESCRIPT("/soap/ajax/40.0/connection.js")}  
{!REQUIRESCRIPT("/soap/ajax/40.0/apex.js")}  

var stage = "{!Opportunity.StageName}";
var type = "{!Opportunity.Type}";
var isClosed = "{!Opportunity.IsClosed}"; 
var recordId = "{!Opportunity.Id}"; 

debugger;
if (isClosed == '1'){
    alert("Opportunity is already closed");
} else {
    if (type != 'Renewal' && type != 'Upsell' && type != 'New Sale'){
        alert("This flow isn't supported by this opportunity type");
    } else {
        window.open('/apex/OppClosedLostFlowPage?id=' + recordId, '_blank');
    }
}
